function calcMatchPoints(pred,result){
  if(!result||result.h===""||result.a==="")return 0;
  if(!pred||pred.h===""||pred.a==="")return 0;
  const rH=parseInt(result.h),rA=parseInt(result.a),pH=parseInt(pred.h),pA=parseInt(pred.a);
  if(pH===rH&&pA===rA)return 3;
  const rW=rH>rA?"H":rH<rA?"A":"D",pW=pH>pA?"H":pH<pA?"A":"D";
  return rW===pW?2:0;
}
function calcSpecialPoints(s,a){
  if(!a)return 0;let p=0;
  if(a.champion&&s?.champion===a.champion)p+=10;
  if(a.scorer&&s?.scorer===a.scorer)p+=8;
  return p;
}

