const tabOff={background:"rgba(245,236,215,0.03)",border:"1px solid rgba(245,236,215,0.05)",color:"rgba(245,236,215,0.3)",padding:"5px 11px",borderRadius:20,fontSize:11,cursor:"pointer",whiteSpace:"nowrap",fontFamily:"'Barlow',sans-serif"};
